  ('bookkeeper-moex-02123', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法規定，關於商業決算報表之查閱與檢查，下列敘述何者正確？', '["商業之利害關係人，得聲請商業會計法之主管機關進行檢查會計帳簿及憑證", "查閱係查閱帳簿報表及憑證，聲請檢查係檢查決算報表", "查閱係由利害關係人自行查閱，聲請檢查則由法院選派檢查員檢查", "商業負責人於利害關係人聲請法院檢查時，若認為違反其商業利益，可拒絕檢查"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02124', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計處理準則關於應收票據與應收帳款之規定，下列何者正確？', '["金額重大之應收關係人票據，不必單獨列示；金額重大之應收關係人帳款，應單獨列示", "已設定擔保的應收帳款，應列為應收帳款的減項", "應收帳款應按現值評價，但到期日在二年以內者，得按帳載金額評價", "應收票據業經貼現者，應予扣除並加註明"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02125', 'bookkeeper', 'bookkeeper-moex-099-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '商業會計處理準則關於其他資產項目定義及評價之規定，下列何者正確？', '["遞延資產，指效益超過一年以上已發生之支出，應由以後各期負擔者，應按未攤銷成本評價", "長期應收票據及款項，按淨變現價值評價", "金額重大之催收款項應單獨列示，不需提列備抵呆帳，以附註說明即可", "閒置資產，指目前未供營業上使用之資產，按未攤銷成本評價"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "81d3ec551896", "answer_pdf_sha1": "452e806b995e", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
